// authenticateRequest validates the gRPC request authentication
func authenticateRequest(ctx context.Context) error {
	// Extract metadata from request
	md, ok := metadata.FromIncomingContext(ctx)
	if !ok {
		return fmt.Errorf("no metadata found")
	}

	// Check for authorization header
	authHeader := md.Get("authorization")
	if len(authHeader) == 0 {
		return fmt.Errorf("authorization header missing")
	}

	// Validate token (in production, use proper JWT validation)
	token := authHeader[0]
	if token == "" {
		return fmt.Errorf("invalid token")
	}

	// In production, validate token against auth service or JWT
	// For this example, we'll check against environment variable
	expectedToken := os.Getenv("GRPC_AUTH_TOKEN")
	if expectedToken == "" {
		return fmt.Errorf("auth token not configured")
	}

	if token != "Bearer "+expectedToken {
		return fmt.Errorf("invalid authorization token")
	}

	return nil
}

// Secure gRPC server setup
func main() {
	// Load TLS credentials
	certFile := os.Getenv("TLS_CERT_FILE")
	keyFile := os.Getenv("TLS_KEY_FILE")
	if certFile == "" || keyFile == "" {
		log.Fatal("TLS certificate files not configured")
	}

	creds, err := credentials.NewServerTLSFromFile(certFile, keyFile)
	if err != nil {
		log.Fatalf("Failed to load TLS credentials: %v", err)
	}

	// Create gRPC server with security options
	server := grpc.NewServer(
		grpc.Creds(creds),
		grpc.KeepaliveParams(keepalive.ServerParameters{
			MaxConnectionIdle: 5 * time.Minute,
			Timeout:           10 * time.Second,
		}),
		grpc.KeepaliveEnforcementPolicy(keepalive.EnforcementPolicy{
			MinTime: 5 * time.Second,
		}),
	)

	// Register service
	RegisterTransactionServiceServer(server, &transactionServiceServer{})

	// Enable reflection for debugging
	reflection.Register(server)

	// Listen on port
	port := os.Getenv("GRPC_PORT")
	if port == "" {
		port = "50051"
	}

	lis, err := net.Listen("tcp", ":"+port)
	if err != nil {
		log.Fatalf("Failed to listen: %v", err)
	}

	log.Printf("Starting gRPC server on port %s", port)
	if err := server.Serve(lis); err != nil {
		log.Fatalf("Failed to serve: %v", err)
	}
}